def verify_message_signature(message_data: bytes, provided_signature: str) -> bool:
    """Verify HMAC signature of the message to ensure integrity and authenticity."""
    secret = os.environ.get("MESSAGE_SIGNING_SECRET", "")
    if not secret:
        logger.error("MESSAGE_SIGNING_SECRET environment variable not set")
